original_code:
module TopModule(
    input wire S,
    input wire R,
    input wire clk,
    output reg Q,
    output reg Q_bar
);
    reg D;

    always @(posedge clk) begin
        if (S && ~R)
            D <= 1'b1;
        else if (~S && R)
            D <= 1'b0;
    end

    assign Q = D;
    assign Q_bar = ~D;
endmodule

